@namespace Lumeo

@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

@* Clearable forces the wrapper branch even while the value is empty: keying
   the branch off "has a value" recreated the <input> element on the first
   typed character (and again when deleting the last one), dropping focus and
   caret mid-typing. Only the clear BUTTON below is value-conditional. *@
@if (Prefix != null || Suffix != null || Variant == InputVariant.Search || Clearable)
{
    @* AdditionalAttributes splat goes on the <input>, not the wrapper div,
       so consumer-passed placeholder / id / autocomplete / aria-label
       reach the actual focusable element. The wrapper has no
       @attributes binding — anything wrapper-targeted (z-index, data-*
       for the visual container) belongs in Class instead. Without this
       routing the Search variant — which forces this wrapper branch
       even for plain `<Input Variant=Search Placeholder="…" />` —
       silently dropped Placeholder onto the div where it has no
       effect (Codex #95 review). *@
    <div class="@WrapperClass">
        @if (Variant == InputVariant.Search && Prefix == null)
        {
            <div class="@($"flex items-center {AccessoryStartPad} pe-1 text-muted-foreground")">
                <Blazicon Svg="Lucide.Search" class="h-4 w-4" />
            </div>
        }
        else if (Prefix != null)
        {
            <div class="@($"flex items-center {AccessoryPad} text-muted-foreground")">@Prefix</div>
        }
        <input @ref="_inputRef"
               name="@Name"
               id="@FormFieldControlId"
               type="@(Variant == InputVariant.Search ? "search" : null)"
               aria-required="@Required.ToString().ToLowerInvariant()"
               aria-invalid="@EffectiveInvalid.ToString().ToLowerInvariant()"
               aria-describedby="@FormFieldDescribedBy"
               maxlength="@MaxLength" class="@WrappedInputClass" value="@_current" @oninput="HandleInput" disabled="@Disabled" @attributes="AdditionalAttributes" />
        @if (Clearable && !string.IsNullOrEmpty(_current))
        {
            <button type="button" class="@($"flex items-center {AccessoryClearPad} text-muted-foreground hover:text-foreground transition-colors")" @onclick="HandleClear" tabindex="-1" aria-label="@L["Common.Clear"]">
                <Blazicon Svg="Lucide.X" class="h-3.5 w-3.5" />
            </button>
        }
        @if (Suffix != null)
        {
            <div class="@($"flex items-center {AccessoryPad} text-muted-foreground")">@Suffix</div>
        }
    </div>
}
else
{
    <input @ref="_inputRef"
           name="@Name"
           id="@FormFieldControlId"
           aria-required="@Required.ToString().ToLowerInvariant()"
           aria-invalid="@EffectiveInvalid.ToString().ToLowerInvariant()"
           aria-describedby="@FormFieldDescribedBy"
           maxlength="@MaxLength" class="@CssClass" value="@_current" @oninput="HandleInput" disabled="@Disabled" @attributes="AdditionalAttributes" />
}

@if (ShowCount)
{
    @* Counter sits below the input wrapper, matching Textarea. *@
    <div class="mt-1 text-xs @CountClass text-end">@CountText</div>
}

@if (!InsideFormField)
{
    @if (EffectiveInvalid && !string.IsNullOrEmpty(ErrorText))
    {
        <p class="mt-1 text-xs text-destructive" role="alert" aria-live="polite">@ErrorText</p>
    }
    else if (!string.IsNullOrEmpty(HelperText))
    {
        <p class="mt-1 text-xs text-muted-foreground">@HelperText</p>
    }
}

@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }
    [Parameter] public EventCallback<ChangeEventArgs> OnInput { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public RenderFragment? Prefix { get; set; }
    [Parameter] public RenderFragment? Suffix { get; set; }
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;
    [Parameter] public Density? Density { get; set; }
    [CascadingParameter] private Density? InheritedDensity { get; set; }
    [Parameter] public bool Clearable { get; set; }
    [Parameter] public EventCallback OnClear { get; set; }
    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }

    /// <summary>Renders a character counter below the input, matching Textarea's pattern.</summary>
    [Parameter] public bool ShowCount { get; set; }

    /// <summary>HTML <c>maxlength</c> on the input plus the limit shown in the counter.
    /// When <c>null</c> and <see cref="ShowCount"/> is true, only the current length is rendered.</summary>
    [Parameter] public int? MaxLength { get; set; }

    /// <summary>Optional custom counter formatter (e.g. <c>c =&gt; $"{c} of 60 chars"</c>).
    /// Default renders <c>42</c> or <c>42/60</c> when <see cref="MaxLength"/> is set.</summary>
    [Parameter] public Func<int, string>? CountFormat { get; set; }
    /// <summary>
    /// Focuses the underlying &lt;input&gt; on first render. The HTML
    /// <c>autofocus</c> attribute doesn't work in Blazor WASM because the
    /// browser's autofocus algorithm runs during initial document parsing —
    /// at parse time the WASM runtime hasn't booted yet and no &lt;input&gt;
    /// exists for it to focus. This parameter uses ElementReference.FocusAsync
    /// in OnAfterRenderAsync(firstRender) which is the canonical workaround.
    /// </summary>
    [Parameter] public bool AutoFocus { get; set; }
    /// <summary>Visual / semantic input variant. <c>Default</c> is the
    /// plain text input. <c>Search</c> auto-renders a search icon prefix,
    /// sets <c>type="search"</c> (gives platforms a clear-button + IME
    /// hints), and applies a search-friendly minimum width so the field
    /// doesn't collapse in narrow flex containers — replaces the
    /// <c>min-w-[180px] max-w-md</c> + manual icon prefix consumers
    /// previously shipped at every search field call-site.</summary>
    [Parameter] public InputVariant Variant { get; set; } = InputVariant.Default;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    public enum InputVariant { Default, Search }

    private ElementReference _inputRef;

    // The live editing value. The <input> renders from this, NOT from the Value
    // [Parameter] directly, so an unrelated parent re-render that re-supplies the
    // same (or stale) Value cannot revert the user's typed text. HandleInput
    // mutates _current and echoes via ValueChanged; the parameter is adopted back
    // into _current only when the PARENT actually changes Value (see OnParametersSet).
    private string? _current;

    // The last Value parameter we observed. Comparing the incoming Value against
    // THIS (not against _current, which our own typing mutates) is what lets us
    // tell a genuine consumer-driven change from a no-op re-render echo.
    private string? _lastValueParam;
    private bool _paramSeeded;

    /// <summary>The underlying &lt;input&gt; element. Exposed for advanced
    /// scenarios that need direct access; prefer <see cref="FocusAsync"/>.</summary>
    public ElementReference Element => _inputRef;

    /// <summary>Programmatically move focus to the input. Safe to call after
    /// the component has rendered at least once.</summary>
    public ValueTask FocusAsync() => _inputRef.FocusAsync();

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // Adopt the FormField's generated id + describedby so the field's <label for>
    // resolves to this input and aria-describedby points at the help/error text
    // (Base UI Field a11y). Null outside a FormField — the id/aria attributes are
    // then omitted, and a consumer-set id via AdditionalAttributes still wins
    // (it splats after these). Empty guard avoids id="" if no id was generated.
    private string? FormFieldControlId => string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId;
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // Character-counter helpers, mirroring Textarea's pattern. These read the
    // live displayed value (_current), not the raw Value parameter, so the count
    // and over-limit state track what the user actually sees after typing.
    private bool IsOverLimit => MaxLength.HasValue && (_current?.Length ?? 0) > MaxLength.Value;
    private string CountClass => IsOverLimit ? "text-destructive" : "text-muted-foreground";
    private string CountText => CountFormat is { } fmt
        ? fmt(_current?.Length ?? 0)
        : MaxLength.HasValue
            ? $"{_current?.Length ?? 0}/{MaxLength}"
            : (_current?.Length ?? 0).ToString();

    private Lumeo.Density EffectiveDensity => Density ?? InheritedDensity ?? Lumeo.Density.Comfortable;

    private string SizeClasses => (Size, EffectiveDensity) switch
    {
        (Lumeo.Size.Sm, Lumeo.Density.Compact)  => "h-7 text-xs px-2",
        (Lumeo.Size.Sm, Lumeo.Density.Spacious) => "h-9 text-xs px-3",
        (Lumeo.Size.Sm, _)                      => "h-8 text-xs px-2.5",
        (Lumeo.Size.Lg, Lumeo.Density.Compact)  => "h-10 text-base px-3",
        (Lumeo.Size.Lg, Lumeo.Density.Spacious) => "h-12 text-base px-5",
        (Lumeo.Size.Lg, _)                      => "h-11 text-base px-4",
        (_, Lumeo.Density.Compact)              => "h-8 text-sm px-2.5",
        (_, Lumeo.Density.Spacious)             => "h-10 text-sm px-4",
        _                                       => "h-9 text-sm px-3"
    };

    private string WrapperSizeClasses => (Size, EffectiveDensity) switch
    {
        (Lumeo.Size.Sm, Lumeo.Density.Compact)  => "h-7 text-xs",
        (Lumeo.Size.Sm, Lumeo.Density.Spacious) => "h-9 text-xs",
        (Lumeo.Size.Sm, _)                      => "h-8 text-xs",
        (Lumeo.Size.Lg, Lumeo.Density.Compact)  => "h-10 text-base",
        (Lumeo.Size.Lg, Lumeo.Density.Spacious) => "h-12 text-base",
        (Lumeo.Size.Lg, _)                      => "h-11 text-base",
        (_, Lumeo.Density.Compact)              => "h-8 text-sm",
        (_, Lumeo.Density.Spacious)             => "h-10 text-sm",
        _                                       => "h-9 text-sm"
    };

    // Accessory edge padding tracks density so prefix/suffix/search-icon/clear
    // affordances tighten/loosen in step with the input body.
    private string AccessoryPad => EffectiveDensity switch
    {
        Lumeo.Density.Compact => "px-2",
        Lumeo.Density.Spacious => "px-4",
        _ => "px-3"
    };
    private string AccessoryStartPad => EffectiveDensity switch
    {
        Lumeo.Density.Compact => "ps-2",
        Lumeo.Density.Spacious => "ps-4",
        _ => "ps-3"
    };
    private string AccessoryClearPad => EffectiveDensity switch
    {
        Lumeo.Density.Compact => "px-1.5",
        Lumeo.Density.Spacious => "px-3",
        _ => "px-2"
    };

    private string WrappedInputSizeClasses => (Size, EffectiveDensity) switch
    {
        (Lumeo.Size.Sm, Lumeo.Density.Compact)  => "px-2 text-xs",
        (Lumeo.Size.Sm, Lumeo.Density.Spacious) => "px-3 text-xs",
        (Lumeo.Size.Sm, _)                      => "px-2.5 text-xs",
        (Lumeo.Size.Lg, Lumeo.Density.Compact)  => "px-3 text-base",
        (Lumeo.Size.Lg, Lumeo.Density.Spacious) => "px-5 text-base",
        (Lumeo.Size.Lg, _)                      => "px-4 text-base",
        (_, Lumeo.Density.Compact)              => "px-2.5 text-sm",
        (_, Lumeo.Density.Spacious)             => "px-4 text-sm",
        _                                       => "px-3 text-sm"
    };

    private string CssClass => Cx.Merge("flex", SizeClasses, "w-full rounded-md border", (EffectiveInvalid ? "border-destructive" : "border-input"), "bg-transparent py-1 transition-colors file:border-0 file:bg-transparent file:text-sm file:font-medium file:text-foreground placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px]", (EffectiveInvalid ? "focus-visible:ring-destructive/20" : "focus-visible:ring-ring"), "disabled:cursor-not-allowed disabled:opacity-50", Class);

    // Search variant adds a min-width floor so the field doesn't collapse
    // in narrow flex containers (the historical consumer fix was
    // `min-w-[180px] max-w-md` per call-site). The min-w-0 default on
    // flex children would otherwise let the wrapper shrink to ~40px when
    // squeezed by siblings.
    private string SearchSizeClass => Variant == InputVariant.Search ? "min-w-[180px] max-w-md" : "";

    private string WrapperClass => Cx.Merge("flex", WrapperSizeClasses, SearchSizeClass, "w-full rounded-md border", (EffectiveInvalid ? "border-destructive" : "border-input"), "bg-transparent transition-colors", (EffectiveInvalid ? "focus-within:ring-[1.5px] focus-within:ring-destructive/20" : "focus-within:ring-[1.5px] focus-within:ring-ring"), "disabled:cursor-not-allowed disabled:opacity-50", Class);

    private string WrappedInputClass => $"flex-1 bg-transparent {WrappedInputSizeClasses} py-1 placeholder:text-muted-foreground focus-visible:outline-none disabled:cursor-not-allowed".Trim();

    protected override void OnParametersSet()
    {
        // Seed the working value from the parameter on first set; thereafter adopt
        // the parameter ONLY when the PARENT actually changed it. HandleInput /
        // HandleClear mutate _current (not Value), so an unrelated parent re-render
        // that re-supplies the same (or a stale uncontrolled) Value does NOT clobber
        // the user's typed text. Compare against _lastValueParam — the last value the
        // parent gave us — not against _current, which our own typing has moved on.
        // (Mirrors the SignaturePad precedent: compare the last param value, not live
        // state.) A controlled parent that echoes back exactly what we emitted lands
        // here with Value == _current already, so re-seeding is a harmless no-op.
        if (!_paramSeeded)
        {
            _current = Value;
            _lastValueParam = Value;
            _paramSeeded = true;
            return;
        }

        if (!string.Equals(Value, _lastValueParam, StringComparison.Ordinal))
        {
            _current = Value;
            _lastValueParam = Value;
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && AutoFocus)
        {
            try { await _inputRef.FocusAsync(); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    private async Task HandleInput(ChangeEventArgs e)
    {
        // Update the live editing value (not the [Parameter]) and echo it out.
        // _lastValueParam stays put so a controlled parent echoing the same string
        // back via OnParametersSet is recognised as "unchanged" and never reverts us.
        _current = e.Value?.ToString();
        await OnInput.InvokeAsync(e);
        await ValueChanged.InvokeAsync(_current);
    }

    private async Task HandleClear()
    {
        _current = "";
        await OnInput.InvokeAsync(new ChangeEventArgs { Value = "" });
        await ValueChanged.InvokeAsync("");
        await OnClear.InvokeAsync();

        // Restore focus to the input. Clicking the clear button moved focus to it,
        // and clearing the value removes the button from the DOM (it is rendered
        // only while the value is non-empty), so focus would otherwise fall to
        // <body> — stranding keyboard users (WCAG 2.4.3). Done after the awaits so
        // the input is guaranteed present (only the button is value-conditional).
        try { await _inputRef.FocusAsync(); }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
    }

}
